In `style.css`, add pressed-state styling:

```css
.pad.pad-pressed {
  /* Full brightness fill with pad color */
  background: var(--pad-color);
  color: #000000; /* black text for contrast against bright bg */
  border-color: var(--pad-color);

  /* Intense halo glow */
  box-shadow:
    0 0 1rem var(--pad-color),
    0 0 2rem var(--pad-color),
    0 0 4rem var(--pad-color),
    inset 0 0 1rem rgba(255,255,255,0.3);

  /* Slight scale-down for pressed feel */
  transform: scale(0.98);

  /* Instant transition on press, but 250ms fade on release is handled by base .pad transition */
}

/* Active state for mouse/touch feedback */
.pad:active:not(.pad-pressed) {
  transform: scale(0.99);
}
```

The base `.pad` already has `transition: all 250ms cubic-bezier(0.4, 0, 0.2, 1);` which handles the fade-out when `.pad-pressed` is removed.

Implementation note: JavaScript will add `.pad-pressed` class on press events and remove it on release events.

In `script.js`, implement audio preloading:

```javascript
// Audio preloading system
const audioCache = {};
const keys = ['1', '2', '3', '4', 'Q', 'W', 'E', 'R', 'A', 'S', 'D', 'F', 'Z', 'X', 'C', 'V'];

// Preload all sounds on page load
function preloadAudio() {
  keys.forEach(key => {
    const audio = new Audio(`src/sounds/${key}.wav`);
    audio.preload = 'auto';
    audioCache[key] = audio;
  });
}

// Play sound with overlap support
function playSound(key) {
  // Clone the cached audio element to allow overlapping plays
  const sound = audioCache[key].cloneNode(true);
  sound.play().catch(err => {
    console.warn(`Audio playback failed for ${key}:`, err);
  });
}

// Initialize on DOM ready
if (document.readyState === 'loading') {
  document.addEventListener('DOMContentLoaded', preloadAudio);
} else {
  preloadAudio();
}
```

This approach:
- Preloads all 16 files into `audioCache` on page load
- Clones the cached Audio object for each play, enabling overlap
- Handles autoplay policy gracefully (first user gesture satisfies requirement)
- Logs warnings if playback fails but doesn't break the app

In `script.js`, add keyboard handling:

```javascript
// Pad element lookup cache
const padElements = {};
keys.forEach(key => {
  padElements[key] = document.querySelector(`[data-key="${key}"]`);
});

// Track which keys are currently pressed
const pressedKeys = new Set();

// Keyboard event handlers
function handleKeyDown(event) {
  const key = event.key.toUpperCase();

  // Ignore if not a mapped key
  if (!keys.includes(key)) return;

  // Ignore OS key-repeat events
  if (event.repeat) return;

  // Prevent default to avoid scrolling, etc.
  event.preventDefault();

  // Mark key as pressed
  pressedKeys.add(key);

  // Trigger visual press
  const pad = padElements[key];
  if (pad) {
    pad.classList.add('pad-pressed');
  }

  // Play sound with overlap
  playSound(key);
}

function handleKeyUp(event) {
  const key = event.key.toUpperCase();

  // Ignore if not a mapped key
  if (!keys.includes(key)) return;

  event.preventDefault();

  // Mark key as released
  pressedKeys.delete(key);

  // Release visual press (triggers 250ms fade via CSS transition)
  const pad = padElements[key];
  if (pad) {
    pad.classList.remove('pad-pressed');
  }
}

// Release all pads on window blur (prevents stuck-lit pads after Cmd-Tab)
function handleBlur() {
  pressedKeys.forEach(key => {
    const pad = padElements[key];
    if (pad) {
      pad.classList.remove('pad-pressed');
    }
  });
  pressedKeys.clear();
}

// Attach listeners
document.addEventListener('keydown', handleKeyDown);
document.addEventListener('keyup', handleKeyUp);
window.addEventListener('blur', handleBlur);
```

In `script.js`, add pointer event handling:

```javascript
// Mouse/touch event handlers for each pad
function initializePadPointerEvents() {
  keys.forEach(key => {
    const pad = padElements[key];
    if (!pad) return;

    // Mouse events
    pad.addEventListener('mousedown', (event) => {
      event.preventDefault(); // Prevent focus/drag artifacts

      pad.classList.add('pad-pressed');
      playSound(key);
    });

    pad.addEventListener('mouseup', () => {
      pad.classList.remove('pad-pressed');
    });

    pad.addEventListener('mouseleave', () => {
      // Release if mouse drags off the pad while held
      pad.classList.remove('pad-pressed');
    });

    // Touch events
    pad.addEventListener('touchstart', (event) => {
      event.preventDefault(); // Prevent ghost clicks and scrolling

      pad.classList.add('pad-pressed');
      playSound(key);
    });

    pad.addEventListener('touchend', (event) => {
      event.preventDefault();
      pad.classList.remove('pad-pressed');
    });

    pad.addEventListener('touchcancel', () => {
      // Handle touch interruption (e.g., system gesture)
      pad.classList.remove('pad-pressed');
    });
  });
}

// Initialize after preload
function init() {
  preloadAudio();
  initializePadPointerEvents();
}

if (document.readyState === 'loading') {
  document.addEventListener('DOMContentLoaded', init);
} else {
  init();
}
```
